export function getAngelNumber(num: string): AngelNumber | undefined {
  return angelNumbers.find(a => a.number === num);
}

export function getAngelNumberBySlug(slug: string): AngelNumber | undefined {
  return angelNumbers.find(a => a.slug === slug);
}

export function getAllAngelNumbers(): AngelNumber[] {
  return angelNumbers;
}

export function getPopularAngelNumbers(): AngelNumber[] {
  const popular = ['000', '111', '222', '333', '444', '555', '666', '777', '888', '999',
    '1111', '2222', '3333', '4444', '5555', '1010', '1212', '1234', '717', '818'];
  return angelNumbers.filter(a => popular.includes(a.number));
}

export function interpretNumber(num: number): { meaning: string; category: string } {
  const s = String(num);
  const digits = s.split('').map(Number);

  // Check for repeating digits
  if (digits.every(d => d === digits[0])) {
    const digitMeanings: Record<number, string> = {
      0: 'infinite potential and new cycles',
      1: 'new beginnings, leadership, and independence',
      2: 'balance, partnership, and cooperation',
      3: 'creativity, self-expression, and joy',
      4: 'stability, hard work, and solid foundations',
      5: 'change, freedom, and adventure',
      6: 'harmony, home, and nurturing',
      7: 'spirituality, inner wisdom, and intuition',
      8: 'abundance, power, and material success',
      9: 'completion, humanitarianism, and letting go',
    };
    return {
      meaning: `This repeating sequence amplifies the energy of ${digits[0]}, which represents ${digitMeanings[digits[0]] || 'a unique vibration'}. The more times a digit repeats, the stronger its message becomes.`,
      category: 'repeating',
    };
  }

  // Check for ascending sequence
  const isAscending = digits.every((d, i) => i === 0 || d === digits[i - 1] + 1);
  if (isAscending && digits.length >= 3) {
    return {
      meaning: 'This ascending sequence represents progress, growth, and forward momentum. You are moving in the right direction, step by step. Trust the process and keep building on your achievements.',
      category: 'ascending',
    };
  }

  // Check for descending sequence
  const isDescending = digits.every((d, i) => i === 0 || d === digits[i - 1] - 1);
  if (isDescending && digits.length >= 3) {
    return {
      meaning: 'This descending sequence represents release, letting go, and simplification. It is time to shed what no longer serves you and return to what truly matters.',
      category: 'descending',
    };
  }

  // Check for mirror/palindrome
  if (s === s.split('').reverse().join('') && s.length >= 3) {
    return {
      meaning: 'This mirror number represents reflection, balance, and alignment. What you put out into the world is coming back to you. Focus on maintaining harmony between your inner world and outer actions.',
      category: 'mirror',
    };
  }

  // Default: combine individual digit meanings
  const digitNames: Record<number, string> = {
    0: 'potential', 1: 'leadership', 2: 'balance', 3: 'creativity',
    4: 'stability', 5: 'change', 6: 'harmony', 7: 'spirituality',
    8: 'abundance', 9: 'completion',
  };
  const uniqueDigits = [...new Set(digits)];
  const themes = uniqueDigits.map(d => digitNames[d] || '').filter(Boolean);
  return {
    meaning: `This number combines the energies of ${themes.join(', ')}. Together, these vibrations suggest a message about integrating these themes in your current life situation.`,
    category: 'combined',
  };
}
